document.addEventListener('DOMContentLoaded', function () { var root = document.getElementById('sosContainer'); if (!root) return; sosStart(root); }); function sosStart(root) { var STORAGE_PREFIX = 'psikorealis_sos_'; var AREA_LABELS = { kepala: 'Kepala Pusing', leher: 'Leher Kaku', dada: 'Dada Sesak', perut: 'Perut Mual' }; /* ---------- Tipe alarm per area tubuh (mekanisme spesifik, bukan acak) ---------- */ var ALARM_TYPES = { kepala: { name: 'Alarm Analitis', mechanism: 'Waktu ancaman terasa nggak jelas bentuknya, otak mengirim sinyalnya ke kepala — bikin kamu mikir berlebihan buat nyari kepastian. Pusing ini sebenarnya tandanya otakmu lagi kerja keras banget nyari jawaban yang belum tentu ada.', quote: 'Kepalamu nggak rusak, dia cuma kerja lembur nyari jawaban yang belum ada.' }, leher: { name: 'Alarm Waspada', mechanism: 'Ketegangan di leher dan bahu biasanya tanda tubuh lagi siaga penuh — otot di area itu erat kaitannya sama respons waspada, kayak tubuh lagi bersiap menghadapi ancaman berikutnya kapan aja datangnya.', quote: 'Otot yang kaku ini lagi menjaga, bukan sedang menghukummu.' }, dada: { name: 'Alarm Siaga Cepat', mechanism: 'Dada sesak itu sinyal klasik dari sistem fight-or-flight-mu yang lagi aktif penuh — jantung berdetak lebih cepat, napas jadi pendek, tubuh nyiapin diri buat \u2018lawan atau lari\u2019, walau ancamannya sebenarnya nggak butuh reaksi sebesar itu.', quote: 'Tubuhmu udah siap perang, padahal yang datang cuma bayangan.' }, perut: { name: 'Alarm Naluri', mechanism: 'Perutmu punya jaringan saraf sendiri yang kadang lebih cepat \u2018merasa\u2019 ancaman daripada otakmu sempat berpikir pakai logika — makanya sering disebut gut feeling. Mual ini tandanya sistem itu udah menyala duluan.', quote: 'Perutmu udah tahu duluan, sebelum kepalamu sempat mikir.' } }; var REFLECTION_POOL = [ 'Kalau rasa ini bisa ngomong, apa yang lagi dia coba lindungin dari kamu?', 'Seandainya temen deket kamu cerita hal yang persis sama, apa yang bakal kamu bilang ke dia?', 'Kapan terakhir kali alarm kayak gini nyala, tapi ternyata yang ditakutin nggak kejadian?', 'Bagian mana dari ketakutan ini yang beneran soal sekarang, dan bagian mana yang soal masa lalu?', 'Apa yang tubuhmu butuhin sekarang, bukan besok?', 'Kalau kamu kasih nama buat rasa ini, kira-kira apa namanya?', 'Apa yang berubah kalau kamu kasih dirimu waktu semalam dulu sebelum ambil kesimpulan?', 'Siapa di hidupmu yang biasanya bikin alarm ini kerasa lebih pelan?', 'Apa satu hal kecil yang bisa kamu lakuin 5 menit ke depan — bukan buat nyelesain semuanya, tapi buat mulai lebih tenang?' ]; var state = { area: null, fact: '', projection: '', breathElapsed: 0, breathTimerId: null, breathIntervalId: null, breathReady: false }; /* ---------- Storage helpers ---------- */ function getStorage(key, fallback) { try { var v = localStorage.getItem(STORAGE_PREFIX + key); return v ? JSON.parse(v) : fallback; } catch (e) { return fallback; } } function setStorage(key, val) { try { localStorage.setItem(STORAGE_PREFIX + key, JSON.stringify(val)); } catch (e) {} } /* ---------- Utility ---------- */ function escapeHtml(str) { return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;'); } function countWords(str) { var t = String(str || '').trim(); if (!t) return 0; return t.split(/\s+/).filter(Boolean).length; } function pickReflectionQuestions() { var lastIndex = getStorage('lastQIndex', 0); var pool = REFLECTION_POOL; var start = (lastIndex + 3) % pool.length; var picked = []; for (var i = 0; i < 3; i++) { picked.push(pool[(start + i) % pool.length]); } setStorage('lastQIndex', start); return picked; } function getAlarmType() { return ALARM_TYPES[state.area] || ALARM_TYPES.dada; } function getGreeting() { var lastVisit = getStorage('lastVisit', null); var sessionCount = getStorage('sessionCount', 0); var areaCounts = getStorage('areaCounts', {}); if (!lastVisit) return { returning: false, sessionCount: sessionCount }; var diffMs = Date.now() - lastVisit; var days = Math.floor(diffMs / 86400000); var timeText; if (days <= 0) timeText = 'hari ini'; else if (days === 1) timeText = 'kemarin'; else timeText = days + ' hari lalu'; var topArea = null, topCount = 0; for (var k in areaCounts) { if (areaCounts.hasOwnProperty(k) && areaCounts[k] > topCount) { topCount = areaCounts[k]; topArea = k; } } return { returning: true, timeText: timeText, topArea: topArea ? AREA_LABELS[topArea] : null, sessionCount: sessionCount }; } function recordSession() { var sessionCount = getStorage('sessionCount', 0) + 1; var areaCounts = getStorage('areaCounts', {}); if (state.area) { areaCounts[state.area] = (areaCounts[state.area] || 0) + 1; } setStorage('sessionCount', sessionCount); setStorage('areaCounts', areaCounts); setStorage('lastVisit', Date.now()); return sessionCount; } /* ---------- Render: Phase 1 ---------- */ function renderPhase1() { var g = getGreeting(); var badge = ''; if (g.returning) { badge = '<div class="sos-returning-badge sos-in sos-in-4">Terakhir kamu di sini <b>' + g.timeText + '</b>.' + (g.topArea ? ' Area yang paling sering kamu pilih: <b>' + g.topArea + '</b>.' : '') + '</div>'; } return ( '<section class="sos-phase active" data-phase="1">' + '<div class="sos-series">' + '<span class="sos-series-dot"></span><span class="sos-series-dot"></span><span class="sos-series-dot"></span>' + '<span class="sos-series-dot sos-series-active"></span>' + '<span class="sos-series-label">Psikorealis Tools Series &middot; 04</span>' + '</div>' + '<svg class="sos-hero-visual" viewBox="0 0 200 200" fill="none">' + '<circle class="sos-hero-ring sos-hero-ring-3" cx="100" cy="100" r="80" stroke="#8E0E3A" stroke-width="1" stroke-dasharray="3 7"/>' + '<circle class="sos-hero-ring sos-hero-ring-2" cx="100" cy="100" r="58" stroke="#C2185B" stroke-width="1.2" stroke-dasharray="3 6"/>' + '<circle class="sos-hero-ring sos-hero-ring-1" cx="100" cy="100" r="36" stroke="#FF2D7A" stroke-width="1.5" stroke-dasharray="4 5"/>' + '<circle class="sos-hero-core" cx="100" cy="100" r="14" fill="#FF2D7A"/>' + '<circle cx="100" cy="100" r="14" fill="none" stroke="#FFFFFF" stroke-width="1.5" opacity="0.4"/>' + '</svg>' + '<span class="sos-eyebrow sos-in sos-in-1">S.O.S \u2014 Regulasi Diri</span>' + '<h1 class="sos-in sos-in-2">Tenangin Diri Dulu, Sebelum Bertindak dari Rasa Panik</h1>' + '<p class="sos-in sos-in-3">Ini bukan kata-kata penyemangat kosong. Ini alat bantu buat ngerti apa yang lagi kejadian di tubuh dan pikiranmu sekarang \u2014 60 detik napas, lalu pisahin fakta dari ketakutan.</p>' + '<div class="sos-chip-row">' + '<span class="sos-chip sos-chip-1">Kepala</span>' + '<span class="sos-chip sos-chip-2">Leher</span>' + '<span class="sos-chip sos-chip-3">Dada</span>' + '<span class="sos-chip sos-chip-4">Perut</span>' + '</div>' + badge + '<div class="sos-meta-row sos-in sos-in-4">' + '<div class="sos-meta"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="9"/><path d="M12 7v5l3 3"/></svg><b>3 menit</b></div>' + '<div class="sos-meta"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg><b>3 langkah</b></div>' + '<div class="sos-meta"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="4" y="10" width="16" height="10" rx="2"/><path d="M8 10V7a4 4 0 018 0v3"/></svg><b>Gratis, tanpa data disimpan</b></div>' + '</div>' + '<div class="sos-in sos-in-5">' + '<button class="sos-btn sos-btn-primary" data-action="goto-2">Mulai Regulasi Mandiri</button>' + '<p class="sos-cred">Disusun dari teknik grounding, body scan &amp; cognitive reframing \u2014 bukan sekadar napas-napas biasa.</p>' + '</div>' + '</section>' ); } /* ---------- Render: Phase 2 ---------- */ function renderPhase2() { return ( '<section class="sos-phase" data-phase="2">' + '<span class="sos-eyebrow">Langkah 1 / 3</span>' + '<h2>Rasa nggak nyaman itu paling kerasa di mana?</h2>' + '<p>Klik area yang paling terasa sekarang.</p>' + '<div class="sos-silhouette-wrap" aria-hidden="true">' + '<svg viewBox="0 0 200 400" xmlns="http://www.w3.org/2000/svg">' + '<circle cx="100" cy="55" r="30" fill="none" stroke="#3A3A44" stroke-width="2"/>' + '<rect x="88" y="82" width="24" height="24" rx="6" fill="none" stroke="#3A3A44" stroke-width="2"/>' + '<rect x="55" y="104" width="90" height="150" rx="24" fill="none" stroke="#3A3A44" stroke-width="2"/>' + '<rect x="30" y="112" width="20" height="110" rx="10" fill="none" stroke="#3A3A44" stroke-width="2"/>' + '<rect x="150" y="112" width="20" height="110" rx="10" fill="none" stroke="#3A3A44" stroke-width="2"/>' + '<rect x="70" y="252" width="24" height="120" rx="10" fill="none" stroke="#3A3A44" stroke-width="2"/>' + '<rect x="106" y="252" width="24" height="120" rx="10" fill="none" stroke="#3A3A44" stroke-width="2"/>' + '<circle class="sos-hotspot" data-area="kepala" cx="100" cy="55" r="16"><title>Kepala Pusing</title></circle>' + '<circle class="sos-hotspot" data-area="leher" cx="100" cy="94" r="13"><title>Leher Kaku</title></circle>' + '<circle class="sos-hotspot" data-area="dada" cx="100" cy="150" r="18"><title>Dada Sesak</title></circle>' + '<circle class="sos-hotspot" data-area="perut" cx="100" cy="205" r="18"><title>Perut Mual</title></circle>' + '</svg>' + '</div>' + '<div class="sos-area-grid">' + areaChip('dada', 'Dada Sesak') + areaChip('leher', 'Leher Kaku') + areaChip('perut', 'Perut Mual') + areaChip('kepala', 'Kepala Pusing') + '</div>' + '<div class="sos-breathing-zone" data-el="breathing-zone">' + '<h2>Ikuti ritme ini dulu, 60 detik aja</h2>' + '<div class="sos-breath-circle-wrap"><div class="sos-breath-circle" data-el="breath-circle">Tarik Napas</div></div>' + '<div class="sos-breath-bar-track"><div class="sos-breath-bar-fill" data-el="breath-bar"></div></div>' + '<div class="sos-breath-progress" data-el="breath-progress">0 / 60 detik</div>' + '</div>' + '<button class="sos-btn sos-btn-primary" data-action="goto-3" data-el="btn-lanjut-2" disabled>Pilih area dulu di atas</button>' + '</section>' ); } function areaChip(key, label) { return '<div class="sos-area-chip" data-action="select-area" data-area="' + key + '">' + label + '</div>'; } /* ---------- Render: Phase 3 ---------- */ function renderPhase3() { return ( '<section class="sos-phase" data-phase="3">' + '<span class="sos-eyebrow">Langkah 2 / 3</span>' + '<h2>Sekarang, pisahin dulu dua hal ini</h2>' + '<p>Nggak perlu rapi, tulis aja apa adanya.</p>' + '<label for="sosFact">Apa yang beneran terjadi (fakta)?</label>' + '<textarea id="sosFact" data-el="input-fact" placeholder="Contoh: Pasangan belum balas chat dari siang."></textarea>' + '<label for="sosProjection">Skenario paling parah yang muncul di kepalamu?</label>' + '<textarea id="sosProjection" data-el="input-projection" placeholder="Contoh: Aku takut dia bosan dan mau ninggalin aku."></textarea>' + '<button class="sos-btn sos-btn-primary" data-action="goto-4" data-el="btn-lanjut-3" disabled>Lihat Hasil</button>' + '</section>' ); } /* ---------- Render: Phase 4 ---------- */ function renderPhase4() { var factSafe = escapeHtml(state.fact || '(tidak diisi)'); var projSafe = escapeHtml(state.projection || '(tidak diisi)'); var questions = pickReflectionQuestions(); var qHtml = questions.map(function (q) { return '<li>' + escapeHtml(q) + '</li>'; }).join(''); var alarm = getAlarmType(); var areaLabel = AREA_LABELS[state.area] || 'Tubuhmu'; var sessionCount = recordSession(); if (typeof gtag === "function") { gtag("event", "hasil_tes", { nama_tool: "sos_regulasi_diri", kombinasi: alarm.name + " x " + areaLabel }); } var factWords = countWords(state.fact); var projWords = countWords(state.projection); var gapHtml = ''; if (factWords > 0 && projWords > 0) { var ratio = projWords / factWords; var gapText; if (ratio >= 1.3) { gapText = 'Bayangan terburukmu jauh lebih \u2018ramai\u2019 dibanding faktanya sendiri. Itu tanda otakmu lagi kerja ekstra keras ngarang cerita \u2014 padahal yang beneran kejadian jauh lebih sedikit dari itu.'; } else if (ratio <= 0.8) { gapText = 'Menariknya, faktanya justru lebih panjang dari bayangan terburukmu. Coba baca ulang fakta yang kamu tulis \u2014 mungkin di situ ada detail yang bikin ketakutanmu terasa lebih besar dari yang seharusnya.'; } else { gapText = 'Fakta dan bayanganmu ini panjangnya hampir sama. Coba baca ulang keduanya pelan-pelan: mana yang beneran udah kejadian, dan mana yang baru sekadar kemungkinan di kepala.'; } gapHtml = '<div class="sos-gap-box">' + '<div class="sos-gap-stat-row">' + '<div class="sos-gap-stat"><b>' + factWords + '</b><span>Kata Fakta</span></div>' + '<div class="sos-gap-stat"><b>' + projWords + '</b><span>Kata Bayangan</span></div>' + '</div>' + '<p class="sos-gap-text">' + gapText + '</p>' + '</div>'; } return ( '<section class="sos-phase" data-phase="4">' + '<div class="sos-chapter">' + '<span class="sos-eyebrow">Hasil</span>' + '<h2>Lembar Refleksi Kamu</h2>' + '<div class="sos-alarm-badge">' + '<svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M12 8v4l3 2"/></svg>' + '<span>' + alarm.name + ' &middot; ' + areaLabel + '</span>' + '</div>' + '</div>' + '<div class="sos-chapter">' + '<div class="sos-result-card sos-card-fact"><h3>Fakta Nyata</h3><p class="sos-user-text">' + factSafe + '</p></div>' + '<div class="sos-result-card sos-card-alarm">' + '<h3>Sistem Alarm Otak Masa Kecil</h3>' + '<p class="sos-user-text">' + projSafe + '</p>' + '<p class="sos-mechanism-line">' + escapeHtml(alarm.mechanism) + '</p>' + '</div>' + '</div>' + (gapHtml ? '<div class="sos-chapter">' + '<h3 class="sos-chapter-h">Jarak Antara Fakta dan Bayangan</h3>' + gapHtml + '</div>' : '') + '<div class="sos-chapter">' + '<div class="sos-quote-card"><p>\u201C' + escapeHtml(alarm.quote) + '\u201D</p></div>' + '</div>' + '<div class="sos-chapter">' + '<h3 class="sos-chapter-h">Bahan Renungan</h3>' + '<ul class="sos-reflection-list">' + qHtml + '</ul>' + '</div>' + '<div class="sos-chapter">' + '<div class="sos-disclaimer">Ini bukan pengganti bantuan profesional. Ini cara berpikir yang dipopulerkan psikologi perilaku, bukan penilaian klinis atas kondisimu. Kalau rasa ini terus berat dan mengganggu keseharianmu, bicara dengan psikolog atau orang yang kamu percaya adalah langkah yang valid.</div>' + '</div>' + '<div class="sos-chapter">' + '<div class="sos-session-counter">Kamu sudah ' + sessionCount + 'x meregulasi diri lewat tools ini.</div>' + '</div>' + '<div class="sos-chapter">' + '<div class="sos-actions-row">' + '<button class="sos-btn sos-btn-secondary sos-no-print" data-action="print">Cetak / Simpan PDF</button>' + '<button class="sos-btn sos-btn-secondary sos-no-print" data-action="restart">Ulangi Sesi</button>' + '</div>' + '</div>' + '<div class="sos-chapter">' + '<div class="sos-followbox">' + '<p>Kalau cara ini membantu, insight kayak gini rutin dibahas di Instagram.</p>' + '<a class="sos-btn sos-btn-ig" href="https://instagram.com/psikorealis" target="_blank" rel="noopener">Follow @psikorealis</a>' + '</div>' + '</div>' + '<div class="sos-chapter">' + '<h3 class="sos-chapter-h">Tes Lainnya dari Psikorealis</h3>' + '<a class="sos-cross-card" href="https://www.psikorealis.id/p/tes-attachment-style-dan-inner-child.html" target="_blank" rel="noopener">' + '<span class="sos-cross-label">Tes Interaktif</span>' + '<span class="sos-cross-title">Peta Pola Diri<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M9 6l6 6-6 6"/></svg></span>' + '<span class="sos-cross-desc">Penasaran kenapa reaksi ini bisa muncul dari dulu? Ini akar mekanismenya.</span>' + '</a>' + '<a class="sos-cross-card" href="https://www.psikorealis.id/p/tes-tipe-overthinking-gratis.html" target="_blank" rel="noopener">' + '<span class="sos-cross-label">Tes Interaktif</span>' + '<span class="sos-cross-title">Tes Tipe Overthinking<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M9 6l6 6-6 6"/></svg></span>' + '<span class="sos-cross-desc">Skenario pikiran yang baru kamu tulis tadi — kenali pola overthinking kamu lebih dalam.</span>' + '</a>' + '<div class="sos-explore-secondary">' + '<a href="https://www.psikorealis.id/p/tes-pola-red-flag-gratis.html" target="_blank" rel="noopener">Peta Pola Red Flag \u2192</a>' + '<a href="https://www.psikorealis.id/p/fakta-psikologi-perilaku-manusia.html" target="_blank" rel="noopener">Fakta Psikologi Perilaku Manusia (insight baru tiap hari) \u2192</a>' + '</div>' + '</div>' + '<div class="sos-chapter" style="border-bottom:none;margin-bottom:0">' + '<div class="sos-teaser">' + '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="4" y="10" width="16" height="10" rx="2"/><path d="M8 10V7a4 4 0 018 0v3"/></svg>' + '<span>Fitur pelacakan pola trigger mingguan — segera hadir.</span>' + '</div>' + '<div class="sos-footer"><span>PSIKOREALIS &middot; HUMAN BEHAVIOR TRANSLATOR</span></div>' + '</div>' + '</section>' ); } /* ---------- Phase transitions ---------- */ function goToPhase(n) { var phases = root.querySelectorAll('.sos-phase'); for (var i = 0; i < phases.length; i++) { phases[i].classList.toggle('active', phases[i].getAttribute('data-phase') === String(n)); } root.scrollIntoView({ behavior: 'smooth', block: 'start' }); } /* ---------- Breathing timer ---------- */ function startBreathing() { if (state.breathIntervalId) return; state.breathElapsed = 0; state.breathReady = false; var circle = root.querySelector('[data-el="breath-circle"]'); var progress = root.querySelector('[data-el="breath-progress"]'); var bar = root.querySelector('[data-el="breath-bar"]'); var btn = root.querySelector('[data-el="btn-lanjut-2"]'); var labels = ['Tarik Napas', 'Tahan', 'Hembuskan']; var labelIdx = 0; if (circle) circle.textContent = labels[0]; var labelIntervalId = setInterval(function () { labelIdx = (labelIdx + 1) % labels.length; if (circle) circle.textContent = labels[labelIdx]; }, 4000); var tickIntervalId = setInterval(function () { state.breathElapsed += 1; if (progress) progress.textContent = state.breathElapsed + ' / 60 detik'; if (bar) bar.style.width = Math.min(100, (state.breathElapsed / 60) * 100) + '%'; if (state.breathElapsed >= 60) { clearInterval(tickIntervalId); clearInterval(labelIntervalId); state.breathReady = true; if (btn) { btn.disabled = false; btn.textContent = 'Lanjut \u2192'; } if (circle) circle.textContent = 'Selesai'; } }, 1000); state.breathIntervalId = tickIntervalId; state.breathTimerId = labelIntervalId; } /* ---------- Event delegation ---------- */ root.addEventListener('click', function (e) { var target = e.target.closest('[data-action]'); if (!target) return; var action = target.getAttribute('data-action'); if (action === 'goto-2') { goToPhase(2); } if (action === 'select-area') { var area = target.getAttribute('data-area'); state.area = area; var chips = root.querySelectorAll('.sos-area-chip'); chips.forEach(function (c) { c.classList.toggle('sos-selected', c.getAttribute('data-area') === area); }); var hotspots = root.querySelectorAll('.sos-hotspot'); hotspots.forEach(function (h) { h.classList.toggle('sos-selected', h.getAttribute('data-area') === area); }); var zone = root.querySelector('[data-el="breathing-zone"]'); if (zone) zone.classList.add('active'); var btn = root.querySelector('[data-el="btn-lanjut-2"]'); if (btn) btn.textContent = 'Tunggu napas selesai dulu...'; startBreathing(); } if (action === 'goto-3') { if (!state.breathReady) return; root.querySelector('[data-phase="3"]').outerHTML = renderPhase3(); goToPhase(3); bindPhase3Inputs(); } if (action === 'goto-4') { if (!state.fact.trim() || !state.projection.trim()) return; root.querySelector('[data-phase="4"]').outerHTML = renderPhase4(); try { var ctaHost4 = root.querySelector('[data-phase="4"]'); if (ctaHost4 && !ctaHost4.querySelector('.pkr-metode-cta')) { ctaHost4.insertAdjacentHTML('beforeend', '<div class="pkr-metode-cta" style="margin-top:16px;padding:14px 16px;border-radius:14px;border:1px solid rgba(255,45,122,.25);background:rgba(255,45,122,.06);font-family:Montserrat,sans-serif;"><a href="/p/metode-psikorealis.html#psi-area" style="font-size:12px;color:#FF9DBF;text-decoration:underline;">Pelajari cara menghadapinya lewat Titik Kosong, bagian dari Metode PSIKOREALIS</a></div>'); } } catch (e) {} goToPhase(4); } if (action === 'print') { window.print(); } if (action === 'restart') { state.area = null; state.fact = ''; state.projection = ''; state.breathElapsed = 0; state.breathReady = false; renderAll(); goToPhase(1); } }); root.addEventListener('input', function (e) { var el = e.target.closest('[data-el]'); if (!el) return; var key = el.getAttribute('data-el'); if (key === 'input-fact') { state.fact = el.value; updateGoto4Button(); } if (key === 'input-projection') { state.projection = el.value; updateGoto4Button(); } }); function updateGoto4Button() { var btn = root.querySelector('[data-el="btn-lanjut-3"]'); if (!btn) return; var ready = state.fact.trim().length > 0 && state.projection.trim().length > 0; btn.disabled = !ready; } function bindPhase3Inputs() { updateGoto4Button(); } /* ---------- Initial render ---------- */ function renderAll() { root.innerHTML = renderPhase1() + renderPhase2() + '<section class="sos-phase" data-phase="3"></section>' + '<section class="sos-phase" data-phase="4"></section>'; } renderAll(); }